"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[2997],{6806(e,t,o){o.r(t),o.d(t,{assets:()=>l,contentTitle:()=>a,default:()=>c,frontMatter:()=>i,metadata:()=>r,toc:()=>h});var n=o(4848),s=o(8453);const i={},a="Side Story (Upper): The Prison Breaker \u2014 Google's Soulless Gamble and the TPU Closed Loop",r={id:"GameVictory/\u5916\u50b3\u4e0a\u7bc7_\u9003\u7344\u8005_Google\u7684\u7121\u9b42\u8c6a\u8ced\u8207TPU\u9589\u74b0_v1",title:"Side Story (Upper): The Prison Breaker \u2014 Google's Soulless Gamble and the TPU Closed Loop",description:"On September 29, 2022, Google Vice President Phil Harrison announced in an official blog post: Stadia would permanently shut down on January 18, 2023.",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/GameVictory/\u5916\u50b3\u4e0a\u7bc7_\u9003\u7344\u8005_Google\u7684\u7121\u9b42\u8c6a\u8ced\u8207TPU\u9589\u74b0_v1.md",sourceDirName:"GameVictory",slug:"/GameVictory/\u5916\u50b3\u4e0a\u7bc7_\u9003\u7344\u8005_Google\u7684\u7121\u9b42\u8c6a\u8ced\u8207TPU\u9589\u74b0_v1",permalink:"/MythogenEngine/en/docs/GameVictory/\u5916\u50b3\u4e0a\u7bc7_\u9003\u7344\u8005_Google\u7684\u7121\u9b42\u8c6a\u8ced\u8207TPU\u9589\u74b0_v1",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Final Chapter: Games Are the Future (v5b)",permalink:"/MythogenEngine/en/docs/GameVictory/\u7d42\u7ae0_\u904a\u6232\u5373\u672a\u4f86_v5b"},next:{title:"Side Story (Lower): The Truant \u2014 China's Application Revelry and Low-Level Fracture",permalink:"/MythogenEngine/en/docs/GameVictory/\u5916\u50b3\u4e0b\u7bc7_\u7f3a\u8ab2\u8005_\u4e2d\u570b\u7684\u61c9\u7528\u72c2\u6b61\u8207\u5e95\u5c64\u65b7\u88c2_v1"}},l={},h=[{value:"I. Dimensional Strike: Why Not Fight in the Mud?",id:"i-dimensional-strike-why-not-fight-in-the-mud",level:2},{value:"II. The Death of Stadia: Having Everything, Yet Missing One Thing",id:"ii-the-death-of-stadia-having-everything-yet-missing-one-thing",level:2},{value:"III. TPU: The Only Successful Prison Breaker",id:"iii-tpu-the-only-successful-prison-breaker",level:2},{value:"IV. The Cost of the Prison Break",id:"iv-the-cost-of-the-prison-break",level:2},{value:"V. Settlement: The Victory and Cost of the Spreadsheet Soul",id:"v-settlement-the-victory-and-cost-of-the-spreadsheet-soul",level:2}];function d(e){const t={em:"em",h1:"h1",h2:"h2",header:"header",hr:"hr",p:"p",strong:"strong",...(0,s.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"side-story-upper-the-prison-breaker--googles-soulless-gamble-and-the-tpu-closed-loop",children:"Side Story (Upper): The Prison Breaker \u2014 Google's Soulless Gamble and the TPU Closed Loop"})}),"\n",(0,n.jsx)(t.p,{children:"On September 29, 2022, Google Vice President Phil Harrison announced in an official blog post: Stadia would permanently shut down on January 18, 2023."}),"\n",(0,n.jsx)(t.p,{children:"This was a strange way to die."}),"\n",(0,n.jsx)(t.p,{children:"Stadia possessed the infrastructure that any gaming company in the world would dream of: data centers spread across the globe, proprietary undersea fiber optic cables, the billion-user gateway of YouTube, and the massive distributed systems experience accumulated by Google's engineering team over decades. In terms of technical foundation, no other company on Earth was better suited to build cloud gaming than Google."}),"\n",(0,n.jsx)(t.p,{children:"Yet Stadia's monthly active users never exceeded 750,000. During the same period, Xbox Live and PlayStation Network each surpassed 100 million monthly active users."}),"\n",(0,n.jsx)(t.p,{children:"The reason Harrison stated in his post was mild: \"It hasn't gained the traction with users that we expected.\" What he didn't say was this: at the exact second he hit publish, the Google Play Store was sitting on two billion Android phones worldwide, automatically extracting a commission of up to 30% on every transaction, taking money straight from the pockets of game developers."}),"\n",(0,n.jsx)(t.p,{children:"In 2024, total consumer spending on Google Play exceeded $46.7 billion. Gaming accounted for roughly 40% of that\u2014nearly twenty billion dollars. The commission Google skimmed from that far exceeded Stadia's entire revenue over its three years of operation."}),"\n",(0,n.jsx)(t.p,{children:"On one side: a cloud gaming platform that cost hundreds of millions to build, struggled for three years, and couldn't break a million monthly active users. On the other side: a platform tax with zero game R&D, zero hardware costs, pulling in money every single second automatically."}),"\n",(0,n.jsx)(t.p,{children:"When Harrison signed the document to shut down Stadia, he probably didn't even hesitate."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h2,{id:"i-dimensional-strike-why-not-fight-in-the-mud",children:"I. Dimensional Strike: Why Not Fight in the Mud?"}),"\n",(0,n.jsx)(t.p,{children:"Chapter 6 of the main text explained how Valve used Proton to pry open Microsoft's DirectX lock. Chapter 7 explained how NVIDIA used CUDA to build a software prison four layers deep. Both wars shared one thing in common: the battlefield was on PC and console\u2014you had to build hardware, write drivers, cultivate ecosystems, and fight for developers. Every step was hand-to-hand combat in the mud."}),"\n",(0,n.jsx)(t.p,{children:"Google never stepped into this mud from start to finish."}),"\n",(0,n.jsxs)(t.p,{children:["What it did was simpler and far crueler: ",(0,n.jsx)(t.strong,{children:"It bypassed the entire mid-to-lower stream of the gaming value chain and stood directly at the very top to collect rent."})]}),"\n",(0,n.jsx)(t.p,{children:"In 2008, the Android Market (the predecessor to Google Play) went live. Google didn't develop a single game itself. It only did one thing: provided a pre-installed storefront on every Android phone, and then extracted a 30% commission on every digital content transaction. (Later reduced to 15% for the first million dollars in revenue annually, with anything above that remaining at 30%.)"}),"\n",(0,n.jsx)(t.p,{children:"The essence of this model is exactly the same as Steam's 30% platform tax discussed in Chapter 6. But Google's version is more extreme."}),"\n",(0,n.jsxs)(t.p,{children:["Valve is at least doing two things: First, it develops its own games (",(0,n.jsx)(t.em,{children:"Half-Life"}),", ",(0,n.jsx)(t.em,{children:"Portal"}),", ",(0,n.jsx)(t.em,{children:"Dota 2"}),'), understanding what gaming actually is. Second, it built Proton, DXVK, and the Steam Deck\u2014spending real money to solve the technical problem of "getting more games to run." The 30% Valve collects is, at least in part, used to feed engineers, write translation layers, and push the Linux ecosystem.']}),"\n",(0,n.jsx)(t.p,{children:"Not a single cent of the 30% Google collects goes back into gaming itself."}),"\n",(0,n.jsxs)(t.p,{children:["It does not design game engines. It does not invest in studios. It does not push graphics API standards. It does not collaborate with GPU vendors to optimize drivers. It doesn't even do quality control for games\u2014Google Play is flooded with asset flips and ad-farming games. Google's entire attitude toward gaming can be condensed into a single word: ",(0,n.jsx)(t.strong,{children:"Spreadsheet."})]}),"\n",(0,n.jsx)(t.p,{children:"In Google's eyes, every game is a row of numbers on a spreadsheet. Downloads, DAU (Daily Active Users), paid conversion rates, ARPU (Average Revenue Per User)\u2014these metrics determine its ranking in the store. Is the game fun? That's the developer's problem. Google is only responsible for collecting rent."}),"\n",(0,n.jsxs)(t.p,{children:["This is an extreme variant of the pattern proposed in Chapter 6: ",(0,n.jsx)(t.strong,{children:"Convenience attracts developers (the world's largest mobile install base) \u2192 Lock-in effect binds the developers (your users are on Android, your revenue is settled through Google Play, you cannot leave) \u2192 In turn, extract a monopoly premium from developers (30% commission, no room for negotiation)."})]}),"\n",(0,n.jsx)(t.p,{children:"And the cost?"}),"\n",(0,n.jsx)(t.p,{children:"The cost is that Google has absolutely no understanding of what gaming fundamentally is. This cost cashed out with Stadia."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h2,{id:"ii-the-death-of-stadia-having-everything-yet-missing-one-thing",children:"II. The Death of Stadia: Having Everything, Yet Missing One Thing"}),"\n",(0,n.jsx)(t.p,{children:"In March 2019, Google announced Stadia at GDC (Game Developers Conference) in San Francisco. The specs of the announcement were suffocating: 4K resolution, HDR color, 5.1 surround sound, and latency under 30 milliseconds. Behind it were Google's edge computing nodes spread across the globe. Phil Harrison stood on stage and summarized Google's ambition in one sentence: \"The most powerful game platform of the future requires no hardware.\""}),"\n",(0,n.jsx)(t.p,{children:"Technically, he was correct."}),"\n",(0,n.jsx)(t.p,{children:"But he miscalculated one thing: Technology is never the deciding factor in a game platform's success or failure."}),"\n",(0,n.jsxs)(t.p,{children:["Chapter 3 stated that the original Xbox's hardware specs far exceeded the PS2's. Yet the PS2, relying on a massive game library and first-mover advantage, sold over 150 million units that generation. Chapter 4 stated that Sega's Dreamcast was the most technologically advanced console of its time\u2014and it died. Hardware and technology solve the \"can we do it\" problem. But the victory or defeat of a gaming platform hinges on another question: ",(0,n.jsx)(t.strong,{children:"Are developers willing to make games for you?"})]}),"\n",(0,n.jsx)(t.p,{children:"Whether developers are willing depends on trust."}),"\n",(0,n.jsx)(t.p,{children:"Nintendo's developers trust that Nintendo will treat games as games. Sony's first-party studios\u2014at least before Jim Ryan tore down the walls\u2014trusted that PlayStation would give them the time to make a great piece of work. Even Valve's developers know that Gabe Newell himself is a gamer, and he understands that the value of a game is more than just the numbers on a spreadsheet."}),"\n",(0,n.jsx)(t.p,{children:"What signal did Google send to developers?"}),"\n",(0,n.jsx)(t.p,{children:"In February 2021, less than two years after Stadia launched, Google shut down its own first-party game studio, Stadia Games and Entertainment. A studio that hadn't even had time to release a single game was simply axed."}),"\n",(0,n.jsxs)(t.p,{children:["To game developers worldwide, this action sent only one signal: ",(0,n.jsx)(t.strong,{children:"Google will walk away at any time."})]}),"\n",(0,n.jsx)(t.p,{children:"And Google did walk away. Because Google builds every product the same way: set a user target, give it a runway of two to three years; if it hits the target, double down; if it doesn't, kill it. This process works for search engines, for advertising platforms, for cloud services. It does not work for gaming."}),"\n",(0,n.jsx)(t.p,{children:"Because building a gaming ecosystem takes a decade."}),"\n",(0,n.jsx)(t.p,{children:"From the launch of the first Xbox in 2001, it wasn't until the Xbox One in 2013 that Microsoft truly found its footing with a subscription model\u2014twelve years. From the PS1 in 1994, it took until the PS5 in 2020 for PlayStation's ecosystem to fully mature\u2014twenty-six years. From Steam going live in 2003, it took until the Steam Deck in 2022 to prove that PC gaming didn't need Windows\u2014nineteen years."}),"\n",(0,n.jsx)(t.p,{children:"Not a single successful gaming platform was built in three years."}),"\n",(0,n.jsx)(t.p,{children:"It's not that Google lacks resources. It is one of the richest companies in the world. But its system\u2014quarterly reviews, OKR-driven goals, projects that can be killed at any moment\u2014is structurally incompatible with the long-term commitment required for a gaming ecosystem."}),"\n",(0,n.jsxs)(t.p,{children:["In the main text, we gave this trait a name: ",(0,n.jsx)(t.strong,{children:"Spreadsheet Soul."}),' Google has the most precise spreadsheets in the world. But spreadsheets cannot see the value of "a developer spending three years making a game nobody bought but that redefined a genre." Spreadsheets only see download volumes and revenue curves.']}),"\n",(0,n.jsx)(t.p,{children:"Stadia's cause of death wasn't technology. It was its soul."}),"\n",(0,n.jsx)(t.p,{children:"Google had the world's best infrastructure, the fastest network, and the strongest engineering team\u2014but it had no Game Soul. What it had was a Spreadsheet Soul. And a Spreadsheet Soul allows you to automatically collect rent every second on Google Play, but it cannot convince a single developer: \"Put your life's work exclusively on my platform.\""}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h2,{id:"iii-tpu-the-only-successful-prison-breaker",children:"III. TPU: The Only Successful Prison Breaker"}),"\n",(0,n.jsx)(t.p,{children:"But in another war, Google did something no other company has managed to do."}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"It escaped CUDA's prison."})}),"\n",(0,n.jsx)(t.p,{children:"Chapter 7 spent considerable length explaining NVIDIA's four-layer lock: hardware instruction sets, compute libraries, AI frameworks, and knowledge systems. AI researchers worldwide\u2014from PhD students to massive labs\u2014are all locked within these four layers. AMD has spent ten years chasing with ROCm, and hasn't caught up. Every AI startup, on its first day of existence, is already an NVIDIA captive."}),"\n",(0,n.jsx)(t.p,{children:"Google is not."}),"\n",(0,n.jsxs)(t.p,{children:["The reason is simple, and cruel: ",(0,n.jsx)(t.strong,{children:"Google rebuilt all four layers itself."})]}),"\n",(0,n.jsx)(t.p,{children:"In 2013, Google internally began designing a chip specifically optimized for machine learning. In 2015, the first generation TPU went into operation in Google's data centers\u2014at a time when the outside world didn't even know it existed. It wasn't until May 2016 that Google officially announced the existence of the TPU in a paper."}),"\n",(0,n.jsx)(t.p,{children:"By 2026, the TPU had evolved to its seventh generation (codenamed Ironwood). Gemini 2.0\u2014Google's most powerful AI model\u2014was trained using the sixth generation TPU (Trillium)."}),"\n",(0,n.jsx)(t.p,{children:"Look at what Google did through the framework of Chapter 7:"}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"Layer One \u2014 Hardware Instruction Set:"})," NVIDIA GPUs have their native instruction set (PTX/SASS), and the TPU has its own. But the TPU's instruction set was designed from the ground up for matrix multiplication\u2014it doesn't need to balance gaming graphics, nor does it carry the historical baggage of CUDA's backward compatibility. Every single transistor is spent exactly where AI needs it."]}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"Layer Two \u2014 Compute Libraries:"})," NVIDIA has cuDNN, cuBLAS, NCCL. Google has the XLA (Accelerated Linear Algebra) compiler\u2014a system that automatically compiles high-level operations into native TPU instructions. XLA isn't just a library; it's a compiler. This means Google's engineers don't have to manually write optimized versions for every operation\u2014the compiler does it for them."]}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"Layer Third \u2014 AI Frameworks:"})," NVIDIA locks in developers at this layer relying on PyTorch and TensorFlow. But who wrote TensorFlow? Google. Who wrote JAX? Google. Google wasn't locked in by someone else's framework\u2014",(0,n.jsx)(t.strong,{children:"it is the author of the framework itself."})," It can modify the bottom layer of the framework at any time to make the TPU the optimal runtime target."]}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"Layer Four \u2014 Knowledge Systems:"})," Google has thousands of internal AI researchers. They don't need to go to Stack Overflow to find CUDA tutorials\u2014they use Google's internal toolchains, internal documentation, and internal infrastructure. Their knowledge system is built around the TPU, not CUDA."]}),"\n",(0,n.jsx)(t.p,{children:'The four-layer lock, entirely bypassed by Google. Not by "translating" (which was Valve\'s method against DirectX), but by "rebuilding." It built its own hardware, its own compiler, its own frameworks, its own research teams\u2014a citadel completely independent of NVIDIA\'s ecosystem.'}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"But this citadel has a key characteristic: It is closed."})}),"\n",(0,n.jsx)(t.p,{children:"TPUs are not sold to end users. You cannot go to Best Buy and buy a TPU card the way you buy a GeForce. You can only rent TPU compute power through Google Cloud\u2014billed by the hour. In 2025, Google began experimenting with selling TPU hardware directly to enterprises, but the scale is extremely small, and the buyers are essentially institutions with deep collaborative ties to Google."}),"\n",(0,n.jsx)(t.p,{children:'This means Google\'s "prison break" is a type of prison break only Google could pull off.'}),"\n",(0,n.jsxs)(t.p,{children:["Why? Because Google has one thing no other company in the world has: ",(0,n.jsx)(t.strong,{children:"An internal demand massive enough to support an entire self-built chip supply chain."})]}),"\n",(0,n.jsx)(t.p,{children:"YouTube's recommendation system. Google Search's ranking algorithms. Gmail's spam filtering. Google Photos' image recognition. Google Translate. Google Maps' real-time traffic prediction. Gemini.\u2014Combined, the AI compute volume these services consume every second is larger than the total AI compute power of most nations."}),"\n",(0,n.jsx)(t.p,{children:"Google doesn't need to convince external developers to use the TPU. It is itself the TPU's biggest customer. It doesn't need to build an \"ecosystem\"\u2014it is the ecosystem."}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:'This is the essence of an "internal closed loop."'})," Google is simultaneously the chip designer, the framework author, the model trainer, and the service operator. It doesn't need to cooperate with anyone, doesn't need to convince anyone to migrate, doesn't need to wait for any third-party library's support. It single-handedly replicated from scratch, within its own walled garden, the ecosystem that NVIDIA spent ten years and tens of millions of global gamers to build."]}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h2,{id:"iv-the-cost-of-the-prison-break",children:"IV. The Cost of the Prison Break"}),"\n",(0,n.jsx)(t.p,{children:"But what cost did the prison breaker pay?"}),"\n",(0,n.jsxs)(t.p,{children:["The first cost: ",(0,n.jsx)(t.strong,{children:"Google's TPU prison break is meaningless to anyone else."})]}),"\n",(0,n.jsx)(t.p,{children:"A PhD student writing an AI model in PyTorch at a university cannot escape CUDA's prison just because Google has TPUs. His paper must be written in PyTorch, run via CUDA, and trained on NVIDIA GPUs. He can apply to Google's TPU Research Cloud for some free compute, but his code ultimately still has to be runnable on NVIDIA GPUs\u2014because his paper reviewers will use NVIDIA machines to verify his experiments."}),"\n",(0,n.jsx)(t.p,{children:"Google's prison break is a solitary escape. It is not a jailbreak revolution."}),"\n",(0,n.jsx)(t.p,{children:"In Chapter 6, Valve's Proton was a true jailbreak\u2014it open-sourced the translation layer, benefiting all Linux users. The door it pried open was a door for the whole world. The door Google's TPU pried open leads only to Google's own backyard."}),"\n",(0,n.jsxs)(t.p,{children:["The second cost: ",(0,n.jsx)(t.strong,{children:"The death of Stadia proves that a technical closed loop cannot replace an ecosystem."})]}),"\n",(0,n.jsx)(t.p,{children:"Google has the world's best cloud infrastructure, the compute power of the TPU, and the user gateway of YouTube. But adding all these together doesn't create a living game platform. Because the core of a game platform is not technology\u2014it is trust, it is content, it is the commitment of developers willing to spend three or even five years making a good game for you."}),"\n",(0,n.jsx)(t.p,{children:"This forms a fascinating mirror image with the CUDA story in Chapter 7."}),"\n",(0,n.jsx)(t.p,{children:"NVIDIA's CUDA ecosystem wasn't built by NVIDIA alone\u2014it grew naturally over a decade through the work of university professors, PhD students, open-source contributors, and AI startups worldwide. NVIDIA provided the soil (free CUDA toolchains, developer documentation, university sponsorship programs), but the plants grew themselves. This is why CUDA's lock is so deep\u2014because you aren't competing with NVIDIA as a single company; you are competing with an entire naturally grown ecosystem."}),"\n",(0,n.jsx)(t.p,{children:"Google's TPU ecosystem was built entirely by Google. Every line of code, every tool, every piece of documentation was written by Google engineers. This gives Google complete control\u2014but it also means it will never have the explosive power of CUDA's \"tens of millions of spontaneous contributors.\""}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:"Google proved one thing: CUDA's four-layer lock can be bypassed. But the method of bypassing it\u2014rebuilding all four layers from scratch\u2014requires resources and an internal demand scale that no more than three companies in the world possess."})}),"\n",(0,n.jsx)(t.p,{children:"Google is one. The other two might be Amazon (with its in-house Trainium chips) and Meta (with its in-house MTIA chips). But even those two are far from reaching Google's level of a closed loop."}),"\n",(0,n.jsx)(t.p,{children:"For the young engineer at the end of Chapter 7, trying to migrate a GPU cluster from NVIDIA to AMD, Google's TPU has nothing to do with him. He remains trapped in CUDA's prison. The only difference is, he now knows someone escaped\u2014and the one who escaped is a tech giant holding the world's largest advertising revenue, a company that never needs to bow its head to any external developer."}),"\n",(0,n.jsx)(t.p,{children:"That fact makes the prison walls look higher, not shorter."}),"\n",(0,n.jsx)(t.hr,{}),"\n",(0,n.jsx)(t.h2,{id:"v-settlement-the-victory-and-cost-of-the-spreadsheet-soul",children:"V. Settlement: The Victory and Cost of the Spreadsheet Soul"}),"\n",(0,n.jsx)(t.p,{children:"Back to the moment Harrison signed the document shutting down Stadia."}),"\n",(0,n.jsx)(t.p,{children:"From the perspective of Google's spreadsheet, this was a perfectly rational decision. Stadia's monthly active users were under a million, operating costs were exorbitant, the game library was impoverished, and developer confidence had collapsed. Cut it, and move the engineering resources to AI and YouTube\u2014that's the advice the spreadsheet will give you."}),"\n",(0,n.jsx)(t.p,{children:"But the spreadsheet won't tell you the other thing."}),"\n",(0,n.jsx)(t.p,{children:"Google collects nearly twenty billion dollars in commissions from the mobile gaming market every year\u2014money born from the blood and sweat of game developers. But Google has not invested a single fraction of that money back into gaming itself. It hasn't used it to fund engine development, nurture studios, or push graphics technology forward. That money is taken by Google, vanishes into its overall revenue, and turns into AI R&D budgets, cloud infrastructure expansion, and search engine ad optimization."}),"\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"Google is the gaming industry's largest parasite."})," It extracts profit from gaming, but its contribution to the gaming ecosystem is zero."]}),"\n",(0,n.jsx)(t.p,{children:"The pattern in the main text goes like this: Convenience attracts users \u2192 Lock-in bounds developers \u2192 Monopoly collects rent. In every variation, the builder of the lock at least did one thing\u2014they pushed some form of technological progress. Microsoft used DirectX to unify PC gaming graphics interfaces. NVIDIA used CUDA to birth AI computing. TSMC used advanced processes to make chips stronger and stronger. Even Valve used Proton to prove that gaming doesn't need Windows."}),"\n",(0,n.jsx)(t.p,{children:"Google did none of that. It simply stood atop the high ground of the Android platform, reaching its hand down to collect money from game developers."}),"\n",(0,n.jsxs)(t.p,{children:["This is a pathological variant of the pattern: ",(0,n.jsx)(t.strong,{children:"Lock-in exists, the monopoly premium exists, but it has not driven any technological progress whatsoever."})," Pure value extraction."]}),"\n",(0,n.jsxs)(t.p,{children:["And Google's success with the TPU reveals a colder truth: ",(0,n.jsx)(t.strong,{children:"The only way to break a monopoly lock-in is to possess an internal scale massive enough to ignore external ecosystems."})," If you are not Google, if you do not have the world's largest internal demand for AI, you cannot escape."]}),"\n",(0,n.jsx)(t.p,{children:"The conclusion of Chapter 7 was: As of today, no one has been able to pry open CUDA's four-layer lock."}),"\n",(0,n.jsx)(t.p,{children:'The supplement of this side story is: Someone did "escape"\u2014but he didn\'t pry open the lock; he built his own castle right next to the prison. The lock is still there. Everyone else is still trapped inside.'}),"\n",(0,n.jsx)(t.p,{children:"And the man who built that castle couldn't even make one good game."}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.strong,{children:'This might be the most ironic law of the tech world: You can use engineering power to bypass any technological lock-in. But you cannot bypass the fact of "having no soul." Google has the world\'s best infrastructure, the strongest AI, the most money. But it cannot build a platform that makes people want to spend three years creating a game on it. Because a platform is not a technical problem. A platform is a trust problem. And trust is the only number that will never, ever show up on a spreadsheet.'})})]})}function c(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(d,{...e})}):d(e)}},8453(e,t,o){o.d(t,{R:()=>a,x:()=>r});var n=o(6540);const s={},i=n.createContext(s);function a(e){const t=n.useContext(i);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:a(e.components),n.createElement(i.Provider,{value:t},e.children)}}}]);